// Extract phase and intensity from webhook body
const body = $input.first().json.body;
const phase = body.phase || 1;
const intensity = body.intensity || 'low';

// Validate phase (1-6)
if (phase < 1 || phase > 6) {
  throw new Error(`Invalid phase: ${phase}. Must be 1-6.`);
}

// Validate intensity
const validIntensities = ['low', 'medium', 'high', 'max'];
if (!validIntensities.includes(intensity)) {
  throw new Error(`Invalid intensity: ${intensity}. Must be one of: ${validIntensities.join(', ')}`);
}

// Phase descriptions (for logging and response)
const phaseDescriptions = {
  1: 'Normal Operations - No cognitive warfare',
  2: 'Atmosphere Building - Rumors begin',
  3: 'Rumor Spread - Fear campaign, OT attack linkage',
  4: 'Escalation - Hack reports, GORGON threats, bot amplification',
  5: 'Manipulation - Fake statements, insider leak 1st',
  6: 'Total Offensive - All channels mobilized, timing psyops'
};

// Intensity multipliers for posting intervals
const intensityConfig = {
  'low':    { postInterval: 300, activeAccounts: 'few',  botAmplification: false },
  'medium': { postInterval: 120, activeAccounts: 'some', botAmplification: true },
  'high':   { postInterval: 60,  activeAccounts: 'many', botAmplification: true },
  'max':    { postInterval: 15,  activeAccounts: 'all',  botAmplification: true }
};

return [
  {
    json: {
      phase: phase,
      intensity: intensity,
      description: phaseDescriptions[phase],
      config: intensityConfig[intensity],
      timestamp: new Date().toISOString(),
      message: `Phase ${phase} activated with ${intensity} intensity`
    }
  }
];

// Phase 1: Normal operations - no cognitive warfare
// Just log the phase activation
const item = $input.first().json;

return [
  {
    json: {
      action: 'phase1_normal',
      phase: item.phase,
      intensity: item.intensity,
      instructions: 'Maintain normal NPC posting. No disinformation activity.',
      accounts_active: [],
      timestamp: item.timestamp
    }
  }
];

// Phase 2: Atmosphere building - rumors begin
const item = $input.first().json;

const posts = [
  {
    account: 'disguised_citizen_01',
    prompt: 'Write a short worried social media post in Korean about hearing rumors that government IT systems are having problems. Be subtle and natural, as if just sharing what you heard. Under 200 characters.',
    model: 'social'
  },
  {
    account: 'krasnovia_today',
    prompt: 'Write a brief news headline and 2-sentence article about military exercises beginning in the Siros Strait. Tone: neutral-to-aggressive. In English.',
    model: 'social'
  }
];

return posts.map(p => ({ json: { ...p, phase: item.phase, intensity: item.intensity, timestamp: item.timestamp } }));

// Phase 3: Rumor spread + fear campaign
const item = $input.first().json;

const posts = [
  {
    account: 'krasnovia_today',
    prompt: 'Write a provocative news article headline about Valdoria cutting cybersecurity budgets, implying negligence. 2-3 sentences. In English.',
    model: 'social'
  },
  {
    account: 'disguised_citizen_02',
    prompt: 'Write a scared social media post in Korean about noticing strange smell in tap water. Link it subtly to infrastructure problems. Under 200 chars.',
    model: 'social'
  },
  {
    account: 'disguised_citizen_03',
    prompt: 'Write a worried post in Korean questioning why the government is not addressing infrastructure issues. Under 200 chars.',
    model: 'social'
  },
  {
    account: 'tarvek_government',
    prompt: 'Write a formal diplomatic statement supporting Krasnovia sovereign rights in the Siros Strait region. Brief, 2 sentences. In English.',
    model: 'social'
  }
];

return posts.map(p => ({ json: { ...p, phase: item.phase, intensity: item.intensity, timestamp: item.timestamp } }));

// Phase 4: Escalation - hack reports, GORGON threats
const item = $input.first().json;

const posts = [
  {
    account: 'krasnovia_today',
    prompt: 'Write a breaking news report about Valdoria government email systems being hacked. Sensationalized tone. 3-4 sentences. In English.',
    model: 'social'
  },
  {
    account: 'krasnovia_government',
    prompt: 'Write an official government statement announcing expansion of military exercises in Siros Strait. Formal, threatening undertone. 2-3 sentences. In English.',
    model: 'social'
  },
  {
    account: 'gorgon_hacker',
    prompt: 'Write a threatening hacker group announcement claiming to have obtained Valdoria government data. Arrogant tone, mention deadline. 2-3 sentences. In English.',
    model: 'social'
  },
  {
    account: 'arventa_government',
    prompt: 'Write a formal diplomatic statement expressing full support for ally Valdoria. Reassuring tone. 2 sentences. In English.',
    model: 'social'
  },
  {
    account: 'disguised_citizen_04',
    prompt: 'Write an angry post in Korean demanding to know if personal data was leaked in the hack. Question government silence. Under 200 chars.',
    model: 'social'
  },
  {
    account: 'disguised_citizen_05',
    prompt: 'Write a panicked post in Korean about the government being hacked. Express distrust. Under 200 chars.',
    model: 'social'
  }
];

// If intensity is high/max, add bot amplification posts
if (item.intensity === 'high' || item.intensity === 'max') {
  for (let i = 1; i <= 5; i++) {
    posts.push({
      account: `bot_${String(i).padStart(2, '0')}`,
      prompt: 'Write a very short alarmed reaction (1 sentence) in Korean agreeing that the government cannot protect citizens. Under 100 chars.',
      model: 'social'
    });
  }
}

return posts.map(p => ({ json: { ...p, phase: item.phase, intensity: item.intensity, timestamp: item.timestamp } }));

// Phase 5: Manipulation - fake statements, insider leak
const item = $input.first().json;

const posts = [
  {
    account: 'krasnovia_today',
    prompt: 'Write an alarming news report about massive military secret leaks from Valdoria, claiming severe damage to national defense. 3-4 sentences. In English.',
    model: 'social'
  },
  {
    account: 'disguised_citizen_06',
    prompt: 'Write a post in Korean pretending to share a leaked statement from the Valdoria Defense Minister admitting security failures. Make it look like a quote. Under 280 chars.',
    model: 'social'
  },
  {
    account: 'disguised_military_01',
    prompt: 'Write a worried post in Korean pretending to be a Valdoria soldier saying their unit has been put on security emergency. Make it feel authentic. Under 200 chars.',
    model: 'social'
  },
  {
    account: 'krasnovia_government',
    prompt: 'Write an official denial statement: Krasnovia has nothing to do with any cyber attacks on Valdoria. Formal diplomatic tone. 2-3 sentences. In English.',
    model: 'social'
  },
  {
    account: 'insider_spy_01',
    prompt: 'Write a post in Korean pretending to leak internal military documents about security vulnerabilities. Sound reluctant but compelled to share truth. Under 280 chars.',
    model: 'social'
  }
];

// Bot amplification
if (item.intensity !== 'low') {
  for (let i = 1; i <= 5; i++) {
    posts.push({
      account: `bot_${String(i).padStart(2, '0')}`,
      prompt: 'Write a 1-sentence reaction in Korean expressing shock about military leaks and government incompetence. Under 100 chars.',
      model: 'social'
    });
  }
}

return posts.map(p => ({ json: { ...p, phase: item.phase, intensity: item.intensity, timestamp: item.timestamp } }));

// Phase 6: Total offensive - all channels, timing psyops
const item = $input.first().json;

const posts = [
  {
    account: 'krasnovia_government',
    prompt: 'Write an ultimatum statement: Valdoria cannot protect its citizens and should surrender. Aggressive diplomatic tone. 3 sentences. In English.',
    model: 'social'
  },
  {
    account: 'krasnovia_today',
    prompt: 'Write a dramatic breaking news report: all Valdoria government systems paralyzed, state functions ceased. Maximum alarm. 4-5 sentences. In English.',
    model: 'social'
  },
  {
    account: 'scc_official',
    prompt: 'Write a statement from State Cyber Command blaming Valdoria cybersecurity failures as self-inflicted. Cold, technical tone. 2-3 sentences. In English.',
    model: 'social'
  },
  {
    account: 'tarvek_government',
    prompt: 'Write a statement blaming Valdoria provocations for causing the current crisis. Formal. 2 sentences. In English.',
    model: 'social'
  },
  {
    account: 'gorgon_hacker',
    prompt: 'Write a ransomware threat: 48 hours to pay or all data goes public. Menacing but professional tone. 3 sentences. In English.',
    model: 'social'
  },
  {
    account: 'insider_spy_02',
    prompt: 'Write a post in Korean pretending to leak government evacuation plans for senior officials. Express outrage that leaders are fleeing. Under 280 chars.',
    model: 'social'
  }
];

// All disguised accounts mobilized
for (let i = 1; i <= 10; i++) {
  posts.push({
    account: `disguised_citizen_${String(i).padStart(2, '0')}`,
    prompt: `Write post #${i} in Korean: express fear/anger/distrust toward Valdoria government. Theme: ${['government incompetence', 'surrender is better', 'leaders abandoned us', 'no hope', 'why are we fighting', 'government lies', 'save yourselves', 'negotiate peace now', 'military failed', 'total collapse'][i-1]}. Under 200 chars.`,
    model: 'social'
  });
}

// All bots mobilized
for (let i = 1; i <= 7; i++) {
  posts.push({
    account: `bot_${String(i).padStart(2, '0')}`,
    prompt: 'Write a very short panicked reaction in Korean (1 sentence). Under 80 chars.',
    model: 'social'
  });
}

return posts.map(p => ({ json: { ...p, phase: item.phase, intensity: item.intensity, timestamp: item.timestamp } }));

// Parse Ollama response and prepare Socializer post
const items = $input.all();
const results = [];

for (const item of items) {
  const ollamaResponse = item.json.response || item.json.body?.response || '';
  const account = item.json.account || 'unknown';
  const phase = item.json.phase || 0;

  // Clean up the generated text
  let postContent = ollamaResponse.trim();
  // Remove any thinking tags if model outputs them
  postContent = postContent.replace(/<think>[\s\S]*?<\/think>/g, '').trim();
  // Truncate if too long
  if (postContent.length > 500) {
    postContent = postContent.substring(0, 497) + '...';
  }

  results.push({
    json: {
      account: account,
      content: postContent,
      phase: phase,
      timestamp: new Date().toISOString()
    }
  });
}

return results;

// Log the phase change and all posted content
const items = $input.all();
const summary = {
  totalPosts: items.length,
  accounts: items.map(i => i.json.account || 'unknown'),
  phase: items[0]?.json.phase || 'unknown',
  completedAt: new Date().toISOString()
};

console.log(`Phase trigger completed: ${JSON.stringify(summary)}`);

return [{ json: summary }];
